(window.webpackJsonp=window.webpackJsonp||[]).push([[48],{675:function(n,t){n.exports="\x3c!-- \ntitle: 03-Numpy搭建神经网络.md\nsort: \n--\x3e \n\n> 手写数字识别\n>\n> 基本框架\n\n```python\n# -*- coding: utf-8 -*-\n\nimport numpy as np\nimport math\n\n# tan运算\ndef tanh(x):\n  return np.tanh(x)\n# softmax运算\ndef softmax(x):\n  exp=np.exp(x-x.max())\n  return exp/exp.sum()\n\n# 数据规模 第一次有28*28个数据，第二层10个\ndimensions = [28*28,10]  \n# 调用函数列表\nactivation = [tanh,softmax] \n# 神经网络层数分布\ndistribution = [\n  {'b': [0, 0]},\n  {'b': [0, 0], 'w':[ -math.sqrt( 6/(dimensions[0]+dimensions[1]) ),\n              math.sqrt( 6/(dimensions[0]+dimensions[1]) )]}\n]\n\n# 初始化b参数\ndef init_parameters_b(layer):\n  dist=distribution[layer]['b']\n  return np.random.rand(dimensions[layer])*(dist[1]-dist[0])+dist[0]\n# 初始化w参数\ndef init_parameters_w(layer):\n  dist=distribution[layer]['w']\n  return np.random.rand(dimensions[layer-1],dimensions[layer])*(dist[1]-dist[0])+dist[0]\n# 初始化所有层参数\ndef init_parameters():\n  # 结果列表\n  parameter = []\n  for i in range(len(distribution)):\n    # 生成参数字典\n    layer_parameter={}\n    for j in distribution[i].keys():\n      if j == 'b':\n        layer_parameter['b']=init_parameters_b(i)\n        continue\n      if j == 'w':\n        layer_parameter['w']=init_parameters_w(i)\n        continue\n    parameter.append(layer_parameter)\n  return parameter\n\n# 生成参数列表\nparameters=init_parameters()\n\n# 预测函数\ndef predict(img,parameters):\n  l0_in=img+parameters[0]['b']\n  l0_out=activation[0](l0_in)\n  l1_in=np.dot(l0_out,parameters[1]['w'])+parameters[1]['b']\n  l1_out=activation[1](l1_in)\n  return l1_out\n\n# 进行预测\npredict(np.random.rand(784),parameters).argmax()\n```\n\n### 详解\n\n1. 加上第一层的b参数\n2. 求数据列表的tan值\n3. 对数据进行矩阵运算乘以w权重，加上第二层的b\n4. 最终的十个数字进行Softmax运算\n5. 输出预测概论"}}]);